  currentResult: null,
  currentOriginalUrl: null,
  autoConvertedFromQuery: false,
  statusHideTimer: null,
  floatingToastTimer: null,
  floatingToastHideTimer: null,
  lastClipboardText: "",
  lastAutoUrl: "",
  activeButtonResetTimers: new WeakMap(),
